      expected = "var foo = \"8 equals 4 + 4\"",
      options = AllOff.copy(
        evaluate = true
      )
    )
  }

  // =========================================================================
  // template_string_with_predefined_constants
  // =========================================================================
  test("template_string_with_predefined_constants".fail) {
    assertCompresses(
      input = """var foo = `This is $${undefined}`;
        var bar = `This is $${NaN}`;
        var baz = `This is $${null}`;
        var foofoo = `This is $${Infinity}`;
        var foobar = "This is $${1/0}";
        var foobaz = 'This is $${1/0}';
        var barfoo = "This is $${NaN}";
        var bazfoo = "This is $${null}";
        var bazbaz = `This is $${1/0}`;
        var barbar = `This is $${0/0}`;
        var barbar = "This is $${0/0}";
        var barber = 'This is $${0/0}';

        var a = `$${4**11}`; // 8 in template vs 7 chars - 4194304
        var b = `$${4**12}`; // 8 in template vs 8 chars - 16777216
        var c = `$${4**14}`; // 8 in template vs 9 chars - 268435456""".stripMargin.trim,
      expected = """var foo = "This is undefined";
        var bar = "This is NaN";
        var baz = "This is null";
        var foofoo = "This is " + 1/0;
        var foobar = "This is $${1/0}";
        var foobaz = 'This is $${1/0}';
        var barfoo = "This is $${NaN}";
        var bazfoo = "This is $${null}";
        var bazbaz = "This is " + 1/0;
        var barbar = "This is NaN";
        var barbar = "This is $${0/0}";
        var barber = 'This is $${0/0}';

        var a = "4194304";
        var b = "16777216"; // Potential for further concatenation
        var c = `$${4**14}`; // Not worth converting""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true
      )
    )
  }

